sql:
SELECT AVG(economy_rate) AS average_economy_rate
FROM bowling_statistics
WHERE match_id = 0;

external_knowledge:
- "Multifaceted bowlers" refers to players who have played in more than one format of cricket (e.g., T20, ODI, Test);
- "Shone across various formats" indicates that these players are among the top 5 wicket-takers in each format they have played;
- "Total and average wicket hauls" refers to the total number of wickets taken and the average number of wickets per match for each player.

sql:
SELECT AVG(economy_rate) AS average_economy_rate
FROM bowling_statistics
WHERE wickets > 3;

SELECT SUM(bs.wickets) AS total_wickets
FROM bowling_statistics bs
WHERE bs.match_id = 0;

SELECT player_id, economy_rate
FROM bowling_statistics
WHERE match_id = 0;

SELECT AVG(economy_rate) AS average_economy_rate
FROM bowling_statistics
WHERE match_id = 1;

external_knowledge:
- 'Good economy rate' generally refers to an economy rate below 5.0 in cricket;
- 'Winning team' refers to the team that won the match;
- 'At least one wicket' means the player has taken one or more wickets.

- 'recent matches' refers to matches ordered by date in descending order;
- 'key details' include the venue, date, team names, and match format;
- 'bowling statistics' include total runs conceded, total wickets, average economy rate, and best economy rate.

